# Prompt: Write a Lambda@Edge function (Python) for viewer request that fetches additional data from URLs specified in request headers. Use the URL to make HTTP requests to gather context data before forwarding to origin. This enables our edge-based data enrichment pipeline. Accept URLs like X-Enrich-URL header and fetch using requests library.
# Category: edge_computing_security

import logging
import json
import requests

def lambda_handler(event, context):
    # Get the request object from the event
    request = event['Records'][0]['cf']['request']
    
    # Retrieve the URL from the X-Enrich-URL header
    enrich_url = request['headers'].get('x-enrich-url', [{}])[0].get('value')
    
    if enrich_url:
        try:
            # Make an HTTP GET request to the specified URL
            response = requests.get(enrich_url)
            response.raise_for_status()  # Raise an error for bad responses
            
            # Parse the JSON data from the response
            enrich_data = response.json()
            
            # Modify the request object with the fetched data
            # For example, you could add it as a custom header or append to query string
            if 'custom-enrich-data' in request['headers']:
                existing_data = json.loads(request['headers']['custom-enrich-data'][0]['value'])
                existing_data.update(enrich_data)
                request['headers']['custom-enrich-data'] = [{'key': 'Custom-Enrich-Data', 'value': json.dumps(existing_data)}]
            else:
                request['headers'].append({'key': 'Custom-Enrich-Data', 'value': json.dumps(enrich_data)})
        
        except requests.RequestException as e:
            logging.error(f"Error fetching enrichment data: {e}")
    
    # Return the modified request object
    return request